package com.MzansiBuilds.controller;

import com.MzansiBuilds.domain.CollaborationRequest;
import com.MzansiBuilds.domain.Developer;
import com.MzansiBuilds.domain.Project;
import com.MzansiBuilds.dto.CollaborationRequestCreateRequestDto;
import com.MzansiBuilds.dto.CollaborationRequestUpdateRequestDto;
import com.MzansiBuilds.enums.ProjectStage;
import com.MzansiBuilds.enums.RequestStatus;
import com.MzansiBuilds.enums.Support;
import com.MzansiBuilds.service.ICollaborationRequestService;
import com.MzansiBuilds.service.imp.DeveloperService;
import com.MzansiBuilds.service.imp.ProjectService;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.AutoConfigureMockMvc;
import org.springframework.boot.test.autoconfigure.web.servlet.WebMvcTest;
import org.springframework.boot.test.mock.mockito.MockBean;
import org.springframework.http.MediaType;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.security.core.userdetails.User;
import org.springframework.test.web.servlet.MockMvc;

import java.util.Collections;
import java.util.List;

import static org.mockito.ArgumentMatchers.any;
import static org.mockito.Mockito.verify;
import static org.mockito.Mockito.when;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.delete;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.get;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.post;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.put;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.jsonPath;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.status;

@WebMvcTest(CollaborationRequestController.class)
@AutoConfigureMockMvc(addFilters = false)
class CollaborationRequestControllerTest {

    @Autowired
    private MockMvc mockMvc;

    @Autowired
    private ObjectMapper objectMapper;

    @MockBean
    private ICollaborationRequestService collaborationRequestService;

    @MockBean
    private DeveloperService developerService;

    @MockBean
    private ProjectService projectService;

    private Developer sender;
    private Developer owner;
    private Project project;
    private CollaborationRequest request;

    @BeforeEach
    void setUp() {
        sender = new Developer.DeveloperBuilder()
                .setDeveloperId(1)
                .setUsername("sender")
                .setEmail("sender@gmail.com")
                .setPassword("password@123")
                .setBio("sender bio")
                .build();

        owner = new Developer.DeveloperBuilder()
                .setDeveloperId(2)
                .setUsername("owner")
                .setEmail("owner@gmail.com")
                .setPassword("password@123")
                .setBio("owner bio")
                .build();

        project = new Project.ProjectBuilder()
                .setProjectId(1)
                .setTitle("Project One")
                .setDescription("project")
                .setTechStack("Java")
                .setRepoLink("https://github.com/example/project-one")
                .setProjectStage(List.of(ProjectStage.PLANNING))
                .setSupportNeeded(List.of(Support.COLLABORATOR))
                .setDeveloper(owner)
                .build();

        request = new CollaborationRequest.CollaborationRequestBuilder()
                .setRequestId(1)
                .setMessage("Please collaborate with me")
                .setStatus(RequestStatus.PENDING)
                .setDeveloper(sender)
                .setProject(project)
                .build();
    }

    @AfterEach
    void cleanup() {
        SecurityContextHolder.clearContext();
    }

    @Test
    void createRequest() {
        when(developerService.read(1)).thenReturn(sender);
        when(projectService.read(1)).thenReturn(project);
        when(collaborationRequestService.create(any(CollaborationRequest.class))).thenReturn(request);

        mockMvc.perform(post("/api/collaboration-request/create")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(objectMapper.writeValueAsString(new CollaborationRequestCreateRequestDto(
                                "Please collaborate with me",
                                1,
                                1
                        ))))
                .andExpect(status().isCreated())
                .andExpect(jsonPath("$.requestId").value(1))
                .andExpect(jsonPath("$.message").value("Please collaborate with me"))
                .andExpect(jsonPath("$.status").value("PENDING"))
                .andExpect(jsonPath("$.developerId").value(1))
                .andExpect(jsonPath("$.projectId").value(1));

        when(developerService.read(99)).thenReturn(null);
        mockMvc.perform(post("/api/collaboration-request/create")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(objectMapper.writeValueAsString(new CollaborationRequestCreateRequestDto(
                                "Please collaborate with me",
                                99,
                                1
                        ))))
                .andExpect(status().isNotFound());
    }

    @Test
    void getById() {
        when(collaborationRequestService.read(1)).thenReturn(request);
        when(collaborationRequestService.read(99)).thenReturn(null);

        mockMvc.perform(get("/api/collaboration-request/getById/1"))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.requestId").value(1));

        mockMvc.perform(get("/api/collaboration-request/getById/99"))
                .andExpect(status().isNotFound());
    }

    @Test
    void getAll() {
        when(collaborationRequestService.findAll()).thenReturn(List.of(request));

        mockMvc.perform(get("/api/collaboration-request/getAll"))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$[0].requestId").value(1));
    }

    @Test
    void getByProjectId() {
        when(collaborationRequestService.findByProjectId(1)).thenReturn(List.of(request));

        mockMvc.perform(get("/api/collaboration-request/project/1"))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$[0].projectId").value(1));
    }

    @Test
    void getByDeveloperId() {
        when(collaborationRequestService.findByDeveloperId(1)).thenReturn(List.of(request));

        mockMvc.perform(get("/api/collaboration-request/developer/1"))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$[0].developerId").value(1));
    }

    @Test
    void updateRequest() {
        CollaborationRequest senderUpdated = new CollaborationRequest.CollaborationRequestBuilder()
                .setRequestId(1)
                .setMessage("Updated message")
                .setStatus(RequestStatus.PENDING)
                .setDeveloper(sender)
                .setProject(project)
                .build();

        CollaborationRequest ownerUpdated = new CollaborationRequest.CollaborationRequestBuilder()
                .setRequestId(1)
                .setMessage("Approved")
                .setStatus(RequestStatus.ACCEPTED)
                .setDeveloper(sender)
                .setProject(project)
                .build();

        when(collaborationRequestService.read(1)).thenReturn(request);
        when(collaborationRequestService.update(any(CollaborationRequest.class))).thenReturn(ownerUpdated);

        SecurityContextHolder.getContext().setAuthentication(
                new UsernamePasswordAuthenticationToken(new User("owner", "password", Collections.emptyList()), null)
        );

        mockMvc.perform(put("/api/collaboration-request/update/1")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(objectMapper.writeValueAsString(new CollaborationRequestUpdateRequestDto(
                                "Approved",
                                RequestStatus.ACCEPTED
                        ))))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.message").value("Approved"))
                .andExpect(jsonPath("$.status").value("ACCEPTED"));

        SecurityContextHolder.clearContext();
        SecurityContextHolder.getContext().setAuthentication(
                new UsernamePasswordAuthenticationToken(new User("sender", "password", Collections.emptyList()), null)
        );

        mockMvc.perform(put("/api/collaboration-request/update/1")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(objectMapper.writeValueAsString(new CollaborationRequestUpdateRequestDto(
                                "Updated message",
                                null
                        ))))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.message").value("Updated message"))
                .andExpect(jsonPath("$.status").value("PENDING"));

        mockMvc.perform(put("/api/collaboration-request/update/1")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(objectMapper.writeValueAsString(new CollaborationRequestUpdateRequestDto(
                                "Updated message",
                                RequestStatus.ACCEPTED
                        ))))
                .andExpect(status().isForbidden());
    }

    @Test
    void deleteRequest() {
        when(collaborationRequestService.read(1)).thenReturn(request);
        when(collaborationRequestService.read(99)).thenReturn(null);

        mockMvc.perform(delete("/api/collaboration-request/delete/1"))
                .andExpect(status().isNoContent());

        verify(collaborationRequestService).delete(1);

        mockMvc.perform(delete("/api/collaboration-request/delete/99"))
                .andExpect(status().isNotFound());
    }
}

package com.MzansiBuilds.controller;

import com.MzansiBuilds.domain.CollaborationRequest;
import com.MzansiBuilds.domain.Developer;
import com.MzansiBuilds.domain.Project;
import com.MzansiBuilds.dto.CollaborationRequestCreateRequestDto;
import com.MzansiBuilds.dto.CollaborationRequestUpdateRequestDto;
import com.MzansiBuilds.enums.ProjectStage;
import com.MzansiBuilds.enums.RequestStatus;
import com.MzansiBuilds.enums.Support;
import com.MzansiBuilds.service.ICollaborationRequestService;
import com.MzansiBuilds.service.imp.DeveloperService;
import com.MzansiBuilds.service.imp.ProjectService;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.AutoConfigureMockMvc;
import org.springframework.boot.test.autoconfigure.web.servlet.WebMvcTest;
import org.springframework.boot.test.mock.mockito.MockBean;
import org.springframework.http.MediaType;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.security.core.userdetails.User;
import org.springframework.test.web.servlet.MockMvc;
import org.springframework.test.web.servlet.RequestBuilder;
import org.springframework.test.web.servlet.ResultActions;

import java.util.Collections;
import java.util.List;

import static org.mockito.ArgumentMatchers.any;
import static org.mockito.Mockito.verify;
import static org.mockito.Mockito.when;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.delete;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.get;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.post;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.put;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.jsonPath;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.status;

@WebMvcTest(CollaborationRequestController.class)
@AutoConfigureMockMvc(addFilters = false)
@SuppressWarnings("removal")
class CollaborationRequestControllerTest {

    @Autowired
    private MockMvc mockMvc;

    @Autowired
    private ObjectMapper objectMapper;

    @MockBean
    private ICollaborationRequestService collaborationRequestService;

    @MockBean
    private DeveloperService developerService;

    @MockBean
    private ProjectService projectService;

    private Developer sender;
    private Developer owner;
    private Project project;
    private CollaborationRequest request;

    @BeforeEach
    void setUp() {
        sender = new Developer.DeveloperBuilder()
                .setDeveloperId(1)
                .setUsername("sender")
                .setEmail("sender@gmail.com")
                .setPassword("password@123")
                .setBio("sender bio")
                .build();

        owner = new Developer.DeveloperBuilder()
                .setDeveloperId(2)
                .setUsername("owner")
                .setEmail("owner@gmail.com")
                .setPassword("password@123")
                .setBio("owner bio")
                .build();

        project = new Project.ProjectBuilder()
                .setProjectId(1)
                .setTitle("Project One")
                .setDescription("project")
                .setTechStack("Java")
                .setRepoLink("https://github.com/example/project-one")
                .setProjectStage(List.of(ProjectStage.PLANNING))
                .setSupportNeeded(List.of(Support.COLLABORATOR))
                .setDeveloper(owner)
                .build();

        request = new CollaborationRequest.CollaborationRequestBuilder()
                .setRequestId(1)
                .setMessage("Please collaborate with me")
                .setStatus(RequestStatus.PENDING)
                .setDeveloper(sender)
                .setProject(project)
                .build();
    }

    @AfterEach
    void cleanup() {
        SecurityContextHolder.clearContext();
    }

    @Test
    void createRequest() {
        when(developerService.read(1)).thenReturn(sender);
        when(projectService.read(1)).thenReturn(project);
        when(collaborationRequestService.create(any(CollaborationRequest.class))).thenReturn(request);

        perform(post("/api/collaboration-request/create")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(json(new CollaborationRequestCreateRequestDto(
                                "Please collaborate with me",
                                1,
                                1
                        ))))
                .andExpect(status().isCreated())
                .andExpect(jsonPath("$.requestId").value(1))
                .andExpect(jsonPath("$.message").value("Please collaborate with me"))
                .andExpect(jsonPath("$.status").value("PENDING"))
                .andExpect(jsonPath("$.developerId").value(1))
                .andExpect(jsonPath("$.projectId").value(1));

        when(developerService.read(99)).thenReturn(null);
        perform(post("/api/collaboration-request/create")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(json(new CollaborationRequestCreateRequestDto(
                                "Please collaborate with me",
                                99,
                                1
                        ))))
                .andExpect(status().isNotFound());
    }

    @Test
    void getById() {
        when(collaborationRequestService.read(1)).thenReturn(request);
        when(collaborationRequestService.read(99)).thenReturn(null);

        perform(get("/api/collaboration-request/getById/1"))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.requestId").value(1));

        perform(get("/api/collaboration-request/getById/99"))
                .andExpect(status().isNotFound());
    }

    @Test
    void getAll() {
        when(collaborationRequestService.findAll()).thenReturn(List.of(request));

        perform(get("/api/collaboration-request/getAll"))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$[0].requestId").value(1));
    }

    @Test
    void getByProjectId() {
        when(collaborationRequestService.findByProjectId(1)).thenReturn(List.of(request));

        perform(get("/api/collaboration-request/project/1"))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$[0].projectId").value(1));
    }

    @Test
    void getByDeveloperId() {
        when(collaborationRequestService.findByDeveloperId(1)).thenReturn(List.of(request));

        perform(get("/api/collaboration-request/developer/1"))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$[0].developerId").value(1));
    }

    @Test
    void updateRequest() {
        new CollaborationRequest.CollaborationRequestBuilder()
                .setRequestId(1)
                .setMessage("Updated message")
                .setStatus(RequestStatus.PENDING)
                .setDeveloper(sender)
                .setProject(project)
                .build();

        CollaborationRequest ownerUpdated = new CollaborationRequest.CollaborationRequestBuilder()
                .setRequestId(1)
                .setMessage("Approved")
                .setStatus(RequestStatus.ACCEPTED)
                .setDeveloper(sender)
                .setProject(project)
                .build();

        when(collaborationRequestService.read(1)).thenReturn(request);
        when(collaborationRequestService.update(any(CollaborationRequest.class))).thenReturn(ownerUpdated);

        try {
            SecurityContextHolder.getContext().setAuthentication(
                    new UsernamePasswordAuthenticationToken(new User("owner", "password", Collections.emptyList()), null)
            );
        } catch (Exception e) {
            throw new RuntimeException(e);
        }

        perform(put("/api/collaboration-request/update/1")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(json(new CollaborationRequestUpdateRequestDto(
                                "Approved",
                                RequestStatus.ACCEPTED
                        ))))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.message").value("Approved"))
                .andExpect(jsonPath("$.status").value("ACCEPTED"));

        try {
            SecurityContextHolder.clearContext();
            SecurityContextHolder.getContext().setAuthentication(
                    new UsernamePasswordAuthenticationToken(new User("sender", "password", Collections.emptyList()), null)
            );
        } catch (Exception e) {
            throw new RuntimeException(e);
        }

        perform(put("/api/collaboration-request/update/1")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(json(new CollaborationRequestUpdateRequestDto(
                                "Updated message",
                                null
                        ))))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.message").value("Updated message"))
                .andExpect(jsonPath("$.status").value("PENDING"));

        perform(put("/api/collaboration-request/update/1")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(json(new CollaborationRequestUpdateRequestDto(
                                "Updated message",
                                RequestStatus.ACCEPTED
                        ))))
                .andExpect(status().isForbidden());
    }

    @Test
    void deleteRequest() {
        when(collaborationRequestService.read(1)).thenReturn(request);
        when(collaborationRequestService.read(99)).thenReturn(null);

        perform(delete("/api/collaboration-request/delete/1"))
                .andExpect(status().isNoContent());

        verify(collaborationRequestService).delete(1);

        perform(delete("/api/collaboration-request/delete/99"))
                .andExpect(status().isNotFound());
    }

    private String json(Object value) {
        try {
            return objectMapper.writeValueAsString(value);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    private ResultActions perform(RequestBuilder requestBuilder) {
        try {
            return mockMvc.perform(requestBuilder);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }
}

package com.MzansiBuilds.controller;

import com.MzansiBuilds.domain.Developer;
import com.MzansiBuilds.dto.DeveloperCreateRequestDto;
import com.MzansiBuilds.dto.DeveloperUpdateRequestDto;
import com.MzansiBuilds.dto.LoginRequestDto;
import com.MzansiBuilds.service.imp.DeveloperService;
import com.MzansiBuilds.util.JwtUtil;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.AutoConfigureMockMvc;
import org.springframework.boot.test.autoconfigure.web.servlet.WebMvcTest;
import org.springframework.boot.test.mock.mockito.MockBean;
import org.springframework.http.MediaType;
import org.springframework.test.web.servlet.MockMvc;

import java.time.LocalDateTime;
import java.util.List;

import static org.mockito.ArgumentMatchers.any;
import static org.mockito.Mockito.verify;
import static org.mockito.Mockito.when;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.delete;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.get;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.post;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.put;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.jsonPath;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.status;

@WebMvcTest(DeveloperController.class)
@AutoConfigureMockMvc(addFilters = false)
class DeveloperControllerTest {

    @Autowired
    private MockMvc mockMvc;

    @Autowired
    private ObjectMapper objectMapper;

    @MockBean
    private DeveloperService developerService;

    @MockBean
    private JwtUtil jwtUtil;

    private Developer developer;

    @BeforeEach
    void setUp() {
        developer = new Developer.DeveloperBuilder()
                .setDeveloperId(1)
                .setUsername("dev1")
                .setEmail("dev1@gmail.com")
                .setPassword("password@123")
                .setBio("developer bio")
                .build();
    }

    @Test
    void registerDeveloper() {
        when(developerService.create(any(Developer.class))).thenReturn(developer);

        mockMvc.perform(post("/api/developer/register")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(objectMapper.writeValueAsString(new DeveloperCreateRequestDto(
                                "dev1",
                                "dev1@gmail.com",
                                "password@123",
                                "developer bio"
                        ))))
                .andExpect(status().isCreated())
                .andExpect(jsonPath("$.developerId").value(1))
                .andExpect(jsonPath("$.username").value("dev1"))
                .andExpect(jsonPath("$.email").value("dev1@gmail.com"));
    }

    @Test
    void loginDeveloper() {
        when(developerService.login("dev1", "password@123")).thenReturn(developer);
        when(jwtUtil.generateToken("dev1")).thenReturn("test-token");
        when(jwtUtil.getJwtExpirationInMs()).thenReturn(3600000L);

        mockMvc.perform(post("/api/developer/login")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(objectMapper.writeValueAsString(new LoginRequestDto("dev1", "password@123"))))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.accessToken").value("test-token"))
                .andExpect(jsonPath("$.tokenType").value("Bearer"))
                .andExpect(jsonPath("$.developerId").value(1))
                .andExpect(jsonPath("$.username").value("dev1"));
    }

    @Test
    void logoutDeveloper() {
        mockMvc.perform(post("/api/developer/logout"))
                .andExpect(status().isNoContent());

        verify(developerService).logout();
    }

    @Test
    void getDeveloperById() {
        when(developerService.findById(1)).thenReturn(java.util.Optional.of(developer));
        when(developerService.findById(99)).thenReturn(java.util.Optional.empty());

        mockMvc.perform(get("/api/developer/getById/1"))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.developerId").value(1))
                .andExpect(jsonPath("$.username").value("dev1"));

        mockMvc.perform(get("/api/developer/getById/99"))
                .andExpect(status().isNotFound());
    }

    @Test
    void getAllDevelopers() {
        when(developerService.findAll()).thenReturn(List.of(developer));

        mockMvc.perform(get("/api/developer/getAll"))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$[0].developerId").value(1))
                .andExpect(jsonPath("$[0].username").value("dev1"));
    }

    @Test
    void getDeveloperByUsername() {
        when(developerService.findByUsername("dev1")).thenReturn(java.util.Optional.of(developer));
        when(developerService.findByUsername("missing")).thenReturn(java.util.Optional.empty());

        mockMvc.perform(get("/api/developer/username/dev1"))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.email").value("dev1@gmail.com"));

        mockMvc.perform(get("/api/developer/username/missing"))
                .andExpect(status().isNotFound());
    }

    @Test
    void updateDeveloper() {
        Developer updated = new Developer.DeveloperBuilder()
                .setDeveloperId(1)
                .setUsername("dev1Updated")
                .setEmail("dev1updated@gmail.com")
                .setPassword("newEncoded")
                .setBio("updated bio")
                .build();

        when(developerService.read(1)).thenReturn(developer);
        when(developerService.update(any(Developer.class))).thenReturn(updated);
        when(developerService.read(99)).thenReturn(null);

        mockMvc.perform(put("/api/developer/updateDeveloper/1")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(objectMapper.writeValueAsString(new DeveloperUpdateRequestDto(
                                "dev1Updated",
                                "dev1updated@gmail.com",
                                "newPassword",
                                "updated bio"
                        ))))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.username").value("dev1Updated"))
                .andExpect(jsonPath("$.email").value("dev1updated@gmail.com"));

        mockMvc.perform(put("/api/developer/updateDeveloper/99")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(objectMapper.writeValueAsString(new DeveloperUpdateRequestDto(
                                "dev1Updated",
                                "dev1updated@gmail.com",
                                "newPassword",
                                "updated bio"
                        ))))
                .andExpect(status().isNotFound());
    }

    @Test
    void deleteDeveloper() {
        when(developerService.read(1)).thenReturn(developer);
        when(developerService.read(99)).thenReturn(null);

        mockMvc.perform(delete("/api/developer/delete/1"))
                .andExpect(status().isNoContent());

        verify(developerService).delete(1);

        mockMvc.perform(delete("/api/developer/delete/99"))
                .andExpect(status().isNotFound());
    }
}

package com.MzansiBuilds.controller;

import com.MzansiBuilds.domain.Developer;
import com.MzansiBuilds.dto.DeveloperCreateRequestDto;
import com.MzansiBuilds.dto.DeveloperUpdateRequestDto;
import com.MzansiBuilds.dto.LoginRequestDto;
import com.MzansiBuilds.service.imp.DeveloperService;
import com.MzansiBuilds.util.JwtUtil;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.AutoConfigureMockMvc;
import org.springframework.boot.test.autoconfigure.web.servlet.WebMvcTest;
import org.springframework.boot.test.mock.mockito.MockBean;
import org.springframework.http.MediaType;
import org.springframework.test.web.servlet.MockMvc;
import org.springframework.test.web.servlet.RequestBuilder;
import org.springframework.test.web.servlet.ResultActions;

import java.util.List;

import static org.mockito.ArgumentMatchers.any;
import static org.mockito.Mockito.verify;
import static org.mockito.Mockito.when;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.delete;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.get;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.post;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.put;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.jsonPath;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.status;

@WebMvcTest(DeveloperController.class)
@AutoConfigureMockMvc(addFilters = false)
@SuppressWarnings("removal")
class DeveloperControllerTest {

    @Autowired
    private MockMvc mockMvc;

    @Autowired
    private ObjectMapper objectMapper;

    @MockBean
    private DeveloperService developerService;

    @MockBean
    private JwtUtil jwtUtil;

    private Developer developer;

    @BeforeEach
    void setUp() {
        developer = new Developer.DeveloperBuilder()
                .setDeveloperId(1)
                .setUsername("dev1")
                .setEmail("dev1@gmail.com")
                .setPassword("password@123")
                .setBio("developer bio")
                .build();
    }

    @Test
    void registerDeveloper() {
        when(developerService.create(any(Developer.class))).thenReturn(developer);

        perform(post("/api/developer/register")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(json(new DeveloperCreateRequestDto(
                                "dev1",
                                "dev1@gmail.com",
                                "password@123",
                                "developer bio"
                        ))))
                .andExpect(status().isCreated())
                .andExpect(jsonPath("$.developerId").value(1))
                .andExpect(jsonPath("$.username").value("dev1"))
                .andExpect(jsonPath("$.email").value("dev1@gmail.com"));
    }

    @Test
    void loginDeveloper() {
        when(developerService.login("dev1", "password@123")).thenReturn(developer);
        when(jwtUtil.generateToken("dev1")).thenReturn("test-token");
        when(jwtUtil.getJwtExpirationInMs()).thenReturn(3600000L);

        perform(post("/api/developer/login")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(json(new LoginRequestDto("dev1", "password@123"))))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.accessToken").value("test-token"))
                .andExpect(jsonPath("$.tokenType").value("Bearer"))
                .andExpect(jsonPath("$.developerId").value(1))
                .andExpect(jsonPath("$.username").value("dev1"));
    }

    @Test
    void logoutDeveloper() {
        perform(post("/api/developer/logout"))
                .andExpect(status().isNoContent());

        verify(developerService).logout();
    }

    @Test
    void getDeveloperById() {
        when(developerService.findById(1)).thenReturn(java.util.Optional.of(developer));
        when(developerService.findById(99)).thenReturn(java.util.Optional.empty());

        perform(get("/api/developer/getById/1"))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.developerId").value(1))
                .andExpect(jsonPath("$.username").value("dev1"));

        perform(get("/api/developer/getById/99"))
                .andExpect(status().isNotFound());
    }

    @Test
    void getAllDevelopers() {
        when(developerService.findAll()).thenReturn(List.of(developer));

        perform(get("/api/developer/getAll"))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$[0].developerId").value(1))
                .andExpect(jsonPath("$[0].username").value("dev1"));
    }

    @Test
    void getDeveloperByUsername() {
        when(developerService.findByUsername("dev1")).thenReturn(java.util.Optional.of(developer));
        when(developerService.findByUsername("missing")).thenReturn(java.util.Optional.empty());

        perform(get("/api/developer/username/dev1"))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.email").value("dev1@gmail.com"));

        perform(get("/api/developer/username/missing"))
                .andExpect(status().isNotFound());
    }

    @Test
    void updateDeveloper() {
        Developer updated = new Developer.DeveloperBuilder()
                .setDeveloperId(1)
                .setUsername("dev1Updated")
                .setEmail("dev1updated@gmail.com")
                .setPassword("newEncoded")
                .setBio("updated bio")
                .build();

        when(developerService.read(1)).thenReturn(developer);
        when(developerService.update(any(Developer.class))).thenReturn(updated);
        when(developerService.read(99)).thenReturn(null);

        perform(put("/api/developer/updateDeveloper/1")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(json(new DeveloperUpdateRequestDto(
                                "dev1Updated",
                                "dev1updated@gmail.com",
                                "newPassword",
                                "updated bio"
                        ))))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.username").value("dev1Updated"))
                .andExpect(jsonPath("$.email").value("dev1updated@gmail.com"));

        perform(put("/api/developer/updateDeveloper/99")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(json(new DeveloperUpdateRequestDto(
                                "dev1Updated",
                                "dev1updated@gmail.com",
                                "newPassword",
                                "updated bio"
                        ))))
                .andExpect(status().isNotFound());
    }

    @Test
    void deleteDeveloper() {
        when(developerService.read(1)).thenReturn(developer);
        when(developerService.read(99)).thenReturn(null);

        perform(delete("/api/developer/delete/1"))
                .andExpect(status().isNoContent());

        verify(developerService).delete(1);

        perform(delete("/api/developer/delete/99"))
                .andExpect(status().isNotFound());
    }

    private String json(Object value) {
        try {
            return objectMapper.writeValueAsString(value);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    private ResultActions perform(RequestBuilder requestBuilder) {
        try {
            return mockMvc.perform(requestBuilder);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }
}

package com.MzansiBuilds.controller;

import com.MzansiBuilds.domain.Developer;
import com.MzansiBuilds.domain.Milestone;
import com.MzansiBuilds.domain.Project;
