import java.time.LocalDateTime;
import java.util.List;

import static org.mockito.ArgumentMatchers.any;
import static org.mockito.Mockito.verify;
import static org.mockito.Mockito.when;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.delete;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.get;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.post;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.put;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.jsonPath;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.status;

@WebMvcTest(MilestoneController.class)
@AutoConfigureMockMvc(addFilters = false)
class MilestoneControllerTest {

    @Autowired
    private MockMvc mockMvc;

    @Autowired
    private ObjectMapper objectMapper;

    @MockBean
    private MilestoneService milestoneService;

    @MockBean
    private ProjectService projectService;

    private Developer developer;
    private Project project;
    private Milestone milestone;

    @BeforeEach
    void setUp() {
        developer = new Developer.DeveloperBuilder()
                .setDeveloperId(1)
                .setUsername("dev1")
                .setEmail("dev1@gmail.com")
                .setPassword("password@123")
                .setBio("developer")
                .build();

        project = new Project.ProjectBuilder()
                .setProjectId(1)
                .setTitle("Project One")
                .setDescription("project")
                .setTechStack("Java")
                .setRepoLink("https://github.com/example/project-one")
                .setProjectStage(List.of(ProjectStage.PLANNING))
                .setSupportNeeded(List.of(Support.COLLABORATOR))
                .setDeveloper(developer)
                .build();

        milestone = new Milestone.MilestoneBuilder()
                .setMilestoneId(1)
                .setTitle("Milestone One")
                .setDescription("Milestone description")
                .setProject(project)
                .build();
    }

    @Test
    void createMilestone() {
        when(projectService.read(1)).thenReturn(project);
        when(milestoneService.create(any(Milestone.class))).thenReturn(milestone);

        mockMvc.perform(post("/api/milestone/create")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(objectMapper.writeValueAsString(new MilestoneCreateRequestDto(
                                "Milestone One",
                                "Milestone description",
                                1
                        ))))
                .andExpect(status().isCreated())
                .andExpect(jsonPath("$.milestoneId").value(1))
                .andExpect(jsonPath("$.title").value("Milestone One"))
                .andExpect(jsonPath("$.projectId").value(1));

        when(projectService.read(99)).thenReturn(null);
        mockMvc.perform(post("/api/milestone/create")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(objectMapper.writeValueAsString(new MilestoneCreateRequestDto(
                                "Milestone One",
                                "Milestone description",
                                99
                        ))))
                .andExpect(status().isNotFound());
    }

    @Test
    void getById() {
        when(milestoneService.read(1)).thenReturn(milestone);
        when(milestoneService.read(99)).thenReturn(null);

        mockMvc.perform(get("/api/milestone/getById/1"))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.milestoneId").value(1))
                .andExpect(jsonPath("$.title").value("Milestone One"));

        mockMvc.perform(get("/api/milestone/getById/99"))
                .andExpect(status().isNotFound());
    }

    @Test
    void getAll() {
        when(milestoneService.findAll()).thenReturn(List.of(milestone));

        mockMvc.perform(get("/api/milestone/getAll"))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$[0].milestoneId").value(1));
    }

    @Test
    void getByProjectId() {
        when(milestoneService.findByProjectId(1)).thenReturn(List.of(milestone));

        mockMvc.perform(get("/api/milestone/project/1"))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$[0].projectId").value(1));
    }

    @Test
    void updateMilestone() {
        Milestone updated = new Milestone.MilestoneBuilder()
                .setMilestoneId(1)
                .setTitle("Milestone Updated")
                .setDescription("Updated description")
                .setProject(project)
                .build();

        when(milestoneService.read(1)).thenReturn(milestone);
        when(milestoneService.update(any(Milestone.class))).thenReturn(updated);
        when(milestoneService.read(99)).thenReturn(null);

        mockMvc.perform(put("/api/milestone/update/1")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(objectMapper.writeValueAsString(new MilestoneUpdateRequestDto(
                                "Milestone Updated",
                                "Updated description"
                        ))))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.title").value("Milestone Updated"));

        mockMvc.perform(put("/api/milestone/update/99")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(objectMapper.writeValueAsString(new MilestoneUpdateRequestDto(
                                "Milestone Updated",
                                "Updated description"
                        ))))
                .andExpect(status().isNotFound());
    }

    @Test
    void deleteMilestone() {
        when(milestoneService.read(1)).thenReturn(milestone);
        when(milestoneService.read(99)).thenReturn(null);

        mockMvc.perform(delete("/api/milestone/delete/1"))
                .andExpect(status().isNoContent());

        verify(milestoneService).delete(1);

        mockMvc.perform(delete("/api/milestone/delete/99"))
                .andExpect(status().isNotFound());
    }
}

