package com.MzansiBuilds.controller;

import com.MzansiBuilds.domain.Developer;
import com.MzansiBuilds.domain.Project;
import com.MzansiBuilds.dto.ProjectCreateRequestDto;
import com.MzansiBuilds.dto.ProjectUpdateRequestDto;
import com.MzansiBuilds.enums.ProjectStage;
import com.MzansiBuilds.enums.Support;
import com.MzansiBuilds.service.imp.DeveloperService;
import com.MzansiBuilds.service.imp.ProjectService;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.AutoConfigureMockMvc;
import org.springframework.boot.test.autoconfigure.web.servlet.WebMvcTest;
import org.springframework.boot.test.mock.mockito.MockBean;
import org.springframework.http.MediaType;
import org.springframework.test.web.servlet.MockMvc;

import java.time.LocalDateTime;
import java.util.List;

import static org.mockito.ArgumentMatchers.any;
import static org.mockito.Mockito.verify;
import static org.mockito.Mockito.when;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.delete;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.get;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.post;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.put;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.jsonPath;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.status;

@WebMvcTest(ProjectController.class)
@AutoConfigureMockMvc(addFilters = false)
class ProjectControllerTest {

    @Autowired
    private MockMvc mockMvc;

    @Autowired
    private ObjectMapper objectMapper;

    @MockBean
    private ProjectService projectService;

    @MockBean
    private DeveloperService developerService;

    private Developer developer;
    private Project project;

    @BeforeEach
    void setUp() {
        developer = new Developer.DeveloperBuilder()
                .setDeveloperId(1)
                .setUsername("dev1")
                .setEmail("dev1@gmail.com")
                .setPassword("password@123")
                .setBio("developer bio")
                .build();

        project = new Project.ProjectBuilder()
                .setProjectId(1)
                .setTitle("Project One")
                .setDescription("Project description")
                .setTechStack("Java, Spring Boot")
                .setRepoLink("https://github.com/example/project-one")
                .setProjectStage(List.of(ProjectStage.PLANNING))
                .setSupportNeeded(List.of(Support.COLLABORATOR))
                .setDeveloper(developer)
                .build();
    }

    @Test
    void createProject() {
        when(developerService.read(1)).thenReturn(developer);
        when(projectService.create(any(Project.class))).thenReturn(project);

        ProjectCreateRequestDto request = new ProjectCreateRequestDto(
                "Project One",
                "Project description",
                "Java, Spring Boot",
                "https://github.com/example/project-one",
                List.of(ProjectStage.PLANNING),
                List.of(Support.COLLABORATOR),
                1
        );

        mockMvc.perform(post("/api/project/create")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(objectMapper.writeValueAsString(request)))
                .andExpect(status().isCreated())
                .andExpect(jsonPath("$.projectId").value(1))
                .andExpect(jsonPath("$.title").value("Project One"))
                .andExpect(jsonPath("$.developerId").value(1));

        when(developerService.read(99)).thenReturn(null);

        mockMvc.perform(post("/api/project/create")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(objectMapper.writeValueAsString(new ProjectCreateRequestDto(
                                "Project One",
                                "Project description",
                                "Java, Spring Boot",
                                "https://github.com/example/project-one",
                                List.of(ProjectStage.PLANNING),
                                List.of(Support.COLLABORATOR),
                                99
                        ))))
                .andExpect(status().isNotFound());
    }

    @Test
    void getProjectById() {
        when(projectService.read(1)).thenReturn(project);
        when(projectService.read(99)).thenReturn(null);

        mockMvc.perform(get("/api/project/getById/1"))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.projectId").value(1))
                .andExpect(jsonPath("$.title").value("Project One"));

        mockMvc.perform(get("/api/project/getById/99"))
                .andExpect(status().isNotFound());
    }

    @Test
    void getAllProjects() {
        when(projectService.findAll()).thenReturn(List.of(project));

        mockMvc.perform(get("/api/project/getAll"))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$[0].projectId").value(1))
                .andExpect(jsonPath("$[0].title").value("Project One"));
    }

    @Test
    void getByDeveloperId() {
        when(projectService.findByDeveloperId(1)).thenReturn(List.of(project));

        mockMvc.perform(get("/api/project/developer/1"))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$[0].developerId").value(1));
    }

    @Test
    void getByStage() {
        when(projectService.findByProjectStage(List.of(ProjectStage.PLANNING))).thenReturn(List.of(project));

        mockMvc.perform(get("/api/project/stage").param("stage", "PLANNING"))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$[0].title").value("Project One"));

        mockMvc.perform(get("/api/project/stage"))
                .andExpect(status().isBadRequest());
    }

    @Test
    void getCelebrationWallProjects() {
